INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'hostels', 'Hostels > Boys: IVH — 1st year, 4-sharing, attached washroom.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'hostels', 'Hostels > Boys: Satpura — 1st year, 3-sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'hostels', 'Hostels > Boys: BH-2 — 2nd year, 2-sharing. CG above 8 can get single room.');
