INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'hostels', 'Hostels > First Year Allocation: IVH or Satpura based on branch. Mess is in the same hostel.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'hostels', 'Hostels > Gate Timing: Main gate closes at 10 PM. Late entry fine of Rs 5,000. Applies to both boys and girls.');
