INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIIT Gwalior', 'mess', 'Mess > Schedule: Weekly mess schedule includes Idli, Dosa, Paratha, Egg Bhurji, Chila for breakfast. Rice, Dal, Sabji, Papad for lunch. Pav Bhaji, Samosa, Pakoda, Chat for snacks. Roti, Rice, Dal, various sabji for dinner. Mix of North Indian cuisine.');
